spec.inputArgumentsSchemaV2:
{
  "type": "object",
  "properties": {
    "mediaPath": {
      "description": "Path/key of the media file inside the bucket",
      "title": "Mediapath",
      "type": "string"
    },
    "mediaType": {
      "description": "MIME type, e.g. 'image/jpeg' or 'video/mp4'",
      "title": "Mediatype",
      "type": "string"
    },
    "assetId": {
      "description": "Asset identifier, e.g. 'AST-SCB-DEL-0788'",
      "title": "Assetid",
      "type": "string"
    },
    "issueText": {
      "default": "",
      "description": "Worker-reported issue text from intake (optional; grounds the vision)",
      "title": "Issuetext",
      "type": "string"
    }
  },
  "required": [
    "mediaPath",
    "mediaType",
    "assetId"
  ]
}

spec.outputArgumentsSchemaV2:
{
  "type": "object",
  "properties": {
    "issue_text_received": {
      "default": "",
      "description": "The worker-reported issue text the agent received (echoed for visibility)",
      "title": "Issue Text Received",
      "type": "string"
    },
    "perception": {
      "additionalProperties": true,
      "description": "Structured fault perception parsed from the vision model",
      "title": "Perception",
      "type": "object"
    },
    "history_match": {
      "additionalProperties": true,
      "description": "How the top fault relates to this asset's prior issue history",
      "title": "History Match",
      "type": "object"
    },
    "history_logged": {
      "default": false,
      "description": "True if a new AssetIssueHistory record was written this run",
      "title": "History Logged",
      "type": "boolean"
    },
    "history_logged_error": {
      "default": "",
      "description": "Error detail if the auto-log write failed (empty when fine)",
      "title": "History Logged Error",
      "type": "string"
    }
  },
  "required": []
}

